import { MakeLogicType, afterMount, connect, kea, listeners, path } from 'kea'
import { loaders } from 'kea-loaders'
import posthog from 'posthog-js'

import { projectLogic } from 'scenes/projectLogic'

import { customPropertyDefinitionsList } from 'products/customer_analytics/frontend/generated/api'
import type { CustomPropertyDefinitionApi } from 'products/customer_analytics/frontend/generated/api.schemas'

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface accountPropertiesInputLogicValues {
    currentProjectId: number | null // projectLogic
    definitions: CustomPropertyDefinitionApi[]
    definitionsLoading: boolean
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface accountPropertiesInputLogicActions {
    loadDefinitions: () => any
    loadDefinitionsFailure: (
        error: string,
        errorObject?: any
    ) => {
        error: string
        errorObject?: any
    }
    loadDefinitionsSuccess: (
        definitions: CustomPropertyDefinitionApi[],
        payload?: any
    ) => {
        definitions: CustomPropertyDefinitionApi[]
        payload?: any
    }
}

export type accountPropertiesInputLogicType = MakeLogicType<
    accountPropertiesInputLogicValues,
    accountPropertiesInputLogicActions
>

export const accountPropertiesInputLogic = kea<accountPropertiesInputLogicType>([
    path([
        'products',
        'customer_analytics',
        'frontend',
        'components',
        'AccountPropertiesInput',
        'accountPropertiesInputLogic',
    ]),
    connect(() => ({
        values: [projectLogic, ['currentProjectId']],
    })),
    loaders(({ values }) => ({
        definitions: [
            [] as CustomPropertyDefinitionApi[],
            {
                loadDefinitions: async (): Promise<CustomPropertyDefinitionApi[]> => {
                    const response = await customPropertyDefinitionsList(String(values.currentProjectId))
                    return response.results
                },
            },
        ],
    })),
    listeners({
        loadDefinitionsFailure: ({ error }) => {
            posthog.captureException(error, { scope: 'accountPropertiesInputLogic.load' })
        },
    }),
    afterMount(({ actions }) => {
        actions.loadDefinitions()
    }),
])
